mapper.insert:
insert into ticket_order (
    user_id, ticket_id, visit_date, quantity, total_amount, order_status
) values (
    #{userId}, #{ticketId}, #{visitDate}, #{quantity}, #{totalAmount}, #{orderStatus}
)

mapper.select:
select id, user_id, ticket_id, visit_date, quantity, total_amount, order_status, create_time
from ticket_order
where id = #{id}

mapper.update:
update ticket_order
set order_status = #{orderStatus}
where id = #{id}
